var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......아무리 그래도 이번엔 장난이 좀 과했어, 알렉스 부전대장.","JPN":"……いくら何でも今回はやり過ぎだ、アレックス副戦隊長。","ENG":"No matter what you say, you went overboard this time, Deputy Commander Alex.","TWN":"……妳這次玩笑開的有點過分了，雅蕾克絲副隊長。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"얌전히 식사만 하겠다고 해서 참석을 허락해 줬는데 이렇게 큰 사고를 치면 어떡하나?","JPN":"大人しく食事をするだけだと言うから許したものを、こんなことをしてどうするつもりだ？","ENG":"You said you just wanted to eat. I would never have let you come if I knew you'd cause so much trouble.","TWN":"妳說妳只是吃個飯就回來，所以我才允許妳參加，但妳卻闖了那麼大的禍！"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"하지만 그림자 세계 안은 너무 지루한걸. 애들 먹을 것도 없고.","JPN":"でも、シャドウ世界はつまらないもの。この子たちが食べる物もないし。","ENG":"But it's too boring to stay in the Shadow World all the time. The kids wanted some food, too.","TWN":"可是暗影世界太無聊了，也沒有東西可以吃。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"물론 이젠 음식을 먹지 않아도 되는 몸이 되긴 했지만......","JPN":"もちろん、今は何も食べなくても問題はないけど……","ENG":"Although we don't need food to sustain ourselves anymore.","TWN":"當然現在的身體，已經不用吃了……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그렇다고 나 혼자만 요즘 애들이랑 노는 건 너무 의리가 없잖아?","JPN":"だからって私だけが若い子たちと遊ぶのも悪いじゃない？","ENG":"Also, I didn't feel right about having fun out here without them.","TWN":"況且我自己去玩也顯得太沒義氣。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"겸사겸사 안에서 지루해하는 애들을 위해 작은 이벤트를 만들어 준 거야.","JPN":"だから、この子たちのために些細なイベントを開いただけなのよ。","ENG":"So I did it for the kids in the Shadow World, as a small entertainment.","TWN":"所以順便為無聊的孩子們準備了小小的驚喜。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아무리 그렇다고 해도 관리자님을 곤란하게 만든 건 잘못된 행동이다, 부전대장.","JPN":"いくらそうだとしても管理者様を困らせるのは間違っていると思わないか、副戦隊長。","ENG":"Even so, you put the Administrator in a very difficult situation, Deputy Commander.","TWN":"即使如此，妳讓管理者大人這麼為難就是有錯，副隊長。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"사과하도록.","JPN":"謝罪をするように。","ENG":"You should apologize.","TWN":"道歉吧。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"후훗. 류드밀라는 너무 딱딱하다니까.","JPN":"ふふっ。リュドミラちゃんは頭が固いんだから。","ENG":"Heh. Lyudmila, you're so stiff.","TWN":"哼，盧德米拉真是太死板了。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그래도 사과를 하라니 해야지. 이번엔 미안했어, 자기야.","JPN":"でも謝罪しろっていうならしないとね。今回はやり過ぎたわ、ごめんなさい。","ENG":"But if you want me to apologize, then I will. I'm sorry, honey.","TWN":"不過我還是會道歉的，這次真的很對不起，親愛的。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"용서해 줄 거지? 나쁜 뜻은 없었어.","JPN":"許してくれるわよね？　悪意はなかったの。","ENG":"You'll forgive me, right? I didn't mean anything bad.","TWN":"你會原諒我吧？我沒有什麼惡意。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"끄응......","JPN":"ううっ……","ENG":"*Groan*","TWN":"呃……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"죄송합니다, 관리자님.","JPN":"管理者様、申し訳ありません。","ENG":"I'm sorry, Administrator.","TWN":"對不起，管理者大人。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"제가 전대원 관리에 좀 더 신경을 썼어야 했는데......","JPN":"私が戦隊員の管理にもう少し気を遣うべきでした。","ENG":"I should have paid more attention to the others.","TWN":"我應該好好管一管隊員的……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아닐세. 애초에 임대료 좀 아껴보자고 자네의 그림자 세계 안에 파티용 산장을 만들어 달라고 했던 것부터 실수였던 것 같아.","JPN":"いや、そもそも賃貸料を減らそうと君のシャドウ世界に\\nパーティー用の山荘を作ったことが間違いだったのだ。","ENG":"No, I shouldn't have asked you to create the cabin inside your Shadow World just to save a small rental fee. It's my fault.","TWN":"沒事。一開始就不該為了省下租金，讓妳在妳的暗影世界建出一個舉辦派對的山莊。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 성야의 살인마라니 대체 그건 뭔가? 테라브레인은 또 어떻게 해킹한 거고.","JPN":"それより、聖夜の殺人鬼とは一体何なんだ？\\nどうやってテラブレインにハッキングを……","ENG":"Anyway, what is this Killer of the Holy Night? And how did you hack into the Terrabrain?","TWN":"話說，耶誕的嫌疑犯到底是什麼？又是怎麼入侵特拉大腦的？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"파티장에서 자네와 얘기한 뒤로 연결이 끊어져서 많이 당황했었네.","JPN":"パーティーで君と話してから接続が途切れて驚いたぞ。","ENG":"I was really confused when I got disconnected after talking to you at the party.","TWN":"在山莊和妳對話後就突然斷線了，讓我很驚慌啊。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"아, 성야의 살인마라는 건 구 관리국 시절에 하던 놀이야.","JPN":"ああ、聖夜の殺人鬼っていうのは旧管理局時代にやってた遊びよ。","ENG":"Ah, the Killer of the Holy Night is a game that we played during the Old Administration.","TWN":"啊，耶誕的嫌疑犯是在舊管理局的時候玩過的。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};